import json
f="30e541a6-f37f-4b74-90df-d611dc8df650.jsonl"
out=[]
with open(f) as fh:
    for line in fh:
        line=line.strip()
        if not line: continue
        try: d=json.loads(line)
        except: continue
        m=d.get("message") or {}
        role=m.get("role") or d.get("type")
        c=m.get("content")
        text=""
        if isinstance(c,str): text=c
        elif isinstance(c,list):
            parts=[]
            for x in c:
                if isinstance(x,dict):
                    if x.get("type")=="text": parts.append(x.get("text",""))
                    elif x.get("type")=="tool_use": parts.append(f"[tool:{x.get('name')}]")
                    elif x.get("type")=="tool_result": parts.append("[tool_result]")
            text=" ".join(p for p in parts if p)
        if role in ("user","assistant") and text.strip():
            # skip pure tool-result/noise user turns
            if text.strip().startswith("[tool_result]"): continue
            out.append((role,text.strip()))
print(f"messages: {len(out)}\n")
for i,(role,t) in enumerate(out):
    cap = 280 if role=="user" else 220
    t=t.replace("\n"," ")
    print(f"--- {i:02d} [{role}] ---")
    print(t[:cap])
